1	export type Cell = [number, number];
2	
3	export const nextGeneration = (cells: Cell[]): Cell[] => {
4	  const key = ([x, y]: Cell): string => `${x},${y}`;
5	  const liveSet = new Set(cells.map(key));
6	
7	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
8	  for (const [x, y] of cells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const neighbor: Cell = [x + dx, y + dy];
13	        const k = key(neighbor);
14	        const existing = neighborCounts.get(k);
15	        if (existing) {
16	          existing.count++;
17	        } else {
18	          neighborCounts.set(k, { cell: neighbor, count: 1 });
19	        }
20	      }
21	    }
22	  }
23	
24	  const survives = (k: string, count: number): boolean =>
25	    count === 3 || (count === 2 && liveSet.has(k));
26	
27	  const nextCells: Cell[] = [];
28	  for (const [k, { cell, count }] of neighborCounts) {
29	    if (survives(k, count)) nextCells.push(cell);
30	  }
31	  return nextCells;
32	};
